svg.script:
var ml=200,pw=1000;
var scr=document.getElementById("scrubber");
var tsl=document.getElementById("ts_label");
var tl=document.getElementById("tooltip");
var pb=document.getElementById("playBtn");
var playing=false,animId=null;
var svgEl=document.querySelector("svg");
function showTip(evt,el){
  var tip=el.getAttribute("data-tip");
  if(!tip)return;
  var parts=tip.split("|");
  tl.innerHTML='<div xmlns="http://www.w3.org/1999/xhtml" style="background:#0f3460;color:#e0e0e0;padding:10px;border:1px solid #e94560;border-radius:4px;font-size:12px;font-family:monospace;white-space:pre;line-height:1.5">'+parts.join('<br/>')+'</div>';
  tl.style.display="block";
  var cx=parseFloat(el.getAttribute("cx"))+20;
  var cy=parseFloat(el.getAttribute("cy"))+20;
  tl.setAttribute("x",Math.min(cx,svgEl.clientWidth-410));
  tl.setAttribute("y",Math.min(cy,svgEl.clientHeight-130));
}
function hideTip(){tl.style.display="none";}
function updateScrub(x){
  x=Math.max(ml,Math.min(x,ml+pw));
  scr.setAttribute("cx",x);
  var p=(x-ml)/pw;
  var all=document.querySelectorAll("circle[data-tip]");
  all.forEach(function(c){
    var cx=parseFloat(c.getAttribute("cx"));
    c.style.display=cx<=x?"":"none";
  });
}
scr.addEventListener("mousedown",function(e){e.preventDefault();function mv(ev){updateScrub(ev.clientX);}function up(){document.removeEventListener("mousemove",mv);document.removeEventListener("mouseup",up);}document.addEventListener("mousemove",mv);document.addEventListener("mouseup",up);});
function togglePlay(){
  playing=!playing;
  pb.textContent=playing?"STOP":"PLAY";
  if(playing){
    var startX=parseFloat(scr.getAttribute("cx"));
    var endX=ml+pw;
    var dur=15000;
    var t0=null;
    function step(ts){
      if(!t0)t0=ts;
      var frac=Math.min((ts-t0)/dur,1);
      var x=startX+(endX-startX)*frac;
      scr.setAttribute("cx",x);
      updateScrub(x);
      if(frac<1)animId=requestAnimationFrame(step);
      else togglePlay();
    }
    animId=requestAnimationFrame(step);
  }else{if(animId)cancelAnimationFrame(animId);}
}
